var StarCodes=Apply(Merge,Values(StarCodesFull));
var	SelfStarCodes={};
	Values(StarCodes).map(v=>SelfStarCodes[v]=v);
	Keys(StarsByMagnitude).map(k=>StarsByMagnitude[k].map(v=>SelfStarCodes[v]=v));
	SelfStarCodes=Merge(StarHRCodes,SelfStarCodes,StarCodes);

var DeclinationsConstellation={};
	Keys(ConstellationDeclinations).map(
		k=>DeclinationsConstellation[ConstellationDeclinations[k].toLowerCase().replaceAll(" ","")]=k.toLowerCase().replaceAll(" ","")
	);

function SimpleStarName(name){
	var name=name.toLowerCase();
		name=name.replaceAll(/(\s|\-|\+)+/g," ");
		name=StringReplace(name,GreekLetterNames);
		name=name.split(" ").map(n=>TransformAccesser(CodesConstellations,LowerCase)(n)).join("").toLowerCase();
		name=UnWhitespaceString(name);
		name=StringReplace(name,DeclinationsConstellation);
	return name;
}

var StarCodeAccesser=TransformAccesser(SelfStarCodes,SimpleStarName);
function StarCode(name){
	return StarCodeAccesser(name);
}

var StarNames=FlipKeysValues(ReverseKeysObject(StarCodes));
var StarNameAccesser=TransformAccesser(StarNames);
function StarName(name){
	var name=StarNameAccesser(StarCode(name),Identity);
	name=name.split(" ").map(n=>In(CodesConstellations,n)?CodesConstellations[n]:n).join(" ");
	name=StringReplace(name,GreekLetterNames);
	return name;
}



var Constellation=function(starcode){
	var constellation=Keys(StarsByMagnitude).filter(k=>In(StarsByMagnitude[k],starcode));
	if(constellation.length)
		return constellation[0];
	else
		return "";
}

NextStarCode=function(starcode){
	var constellation=Constellation(starcode);
	if(constellation){
		var stars=StarsByMagnitude[constellation];
		var i=stars.indexOf(starcode);
		if(i<0||i>=stars.length)
			return "";
		else
			return stars[i+1];
	}
	else
		return "";
}

function ConstellationDeclinate(star){
	if(!ConstellationDeclinate.l){
		ConstellationDeclinate.l={};
		Keys(ConstellationDeclinations).map(function(k){
			ConstellationDeclinate.l[k+" "]=(ConstellationDeclinations[k]+" ");
		})
	}
	return UnPosfix(StringReplace(star+" ",ConstellationDeclinate.l)," ");
/*
Declinate once
ConstellationDeclinate("alpha Hydra")
"alpha Hydrae"

and only once (no hydraae)
ConstellationDeclinate("alpha Hydrae")
"alpha Hydrae"
*/
}

function NextStar(starname){
	var nextstar=StarName(NextStarCode(StarCode(starname)));
		nextstar=StringReplace(nextstar,GreekLetterNames);
		nextstar=ConstellationDeclinate(nextstar);
	return nextstar;
}


var HighlightableStars=Keys(StarCodes);
